-- Hapus semua lowongan dan aplikasi, lalu insert ~50 lowongan dummy
-- Jalankan: mysql -u root challora_recruitment < database/seed_dummy_jobs.sql

USE challora_recruitment;

DELETE FROM job_skills;
DELETE FROM job_benefits;
DELETE FROM applications;
DELETE FROM jobs;

SET @hr_id = (SELECT id FROM users WHERE role = 'hr' LIMIT 1);

