INSERT INTO jobs (title, short_description, description, location, provinsi, kota, kecamatan, salary_range, min_salary, max_salary, job_type, min_education, is_urgent, deadline, max_applicants, skills_json, benefits_json, created_by) VALUES
('Software Engineer', 'Software Engineer untuk pengembangan web. PHP, JavaScript, database, Git. Fresh graduate dipersilakan.', 'Kami mencari Software Engineer yang berpengalaman dalam pengembangan web dan aplikasi. Anda akan bergabung dengan tim engineering yang dinamis untuk membangun produk-produk digital berkualitas.\n\nKualifikasi: Menguasai PHP dan JavaScript, familiar dengan database MySQL/PostgreSQL, memahami version control (Git). Pengalaman dengan framework seperti Laravel atau React akan menjadi nilai plus. Fresh graduate dengan portofolio yang menarik dipersilakan melamar.\n\nTanggung jawab: Mengembangkan fitur baru, debugging, code review, dan berkolaborasi dengan tim product serta design. Kami menawarkan lingkungan kerja yang mendukung learning dan growth.', 'Kelapa Gading', 'DKI Jakarta', 'Jakarta Utara', 'Kelapa Gading', '8-15 juta', 8, 15, 'full_time', 's1', 0, NULL, NULL, '["PHP","JavaScript","MySQL","Git"]', '["BPJS","THR","WFH"]', @hr_id),
('Frontend Developer', 'Frontend Developer dengan HTML/CSS, JavaScript, React atau Vue. Remote work tersedia.', 'Bergabung sebagai Frontend Developer di tim kami. Anda akan bertanggung jawab membangun interface yang responsif, modern, dan user-friendly.\n\nRequirements: Mahir HTML5, CSS3, JavaScript (ES6+). Pengalaman dengan React, Vue, atau framework modern lainnya. Memahami responsive design, cross-browser compatibility, dan basic SEO. Familiar dengan tools seperti Figma, Git, dan build tools (Webpack/Vite).\n\nWe offer: Remote work, fleksibel jam kerja, dan lingkungan kolaboratif. Anda akan bekerja dengan designer dan backend team untuk deliver produk terbaik.', 'Remote', NULL, NULL, NULL, '7-12 juta', 7, 12, 'full_time', 's1', 1, NULL, 50, '["HTML","CSS","JavaScript","React","Vue"]', '["BPJS","WFH","Cuti Tahunan"]', @hr_id),
('Data Analyst', 'Analisis data bisnis, report dan dashboard. Excel, SQL, Python. Pengalaman minimal 1 tahun.', 'Posisi Data Analyst untuk mengubah data menjadi insight yang actionable. Anda akan bekerja dengan berbagai stakeholder untuk memahami kebutuhan bisnis dan menyediakan analisis yang mendukung keputusan.\n\nTanggung jawab: Mengumpulkan dan membersihkan data, membuat report rutin, membangun dashboard interaktif, dan melakukan ad-hoc analysis. Tools yang digunakan: Excel (advanced), SQL untuk query data, Python/R untuk analysis, Tableau atau sejenisnya untuk visualisasi.\n\nKualifikasi: S1 bidang terkait (Statistik, Ekonomi, IT, atau sejenis), pengalaman 1+ tahun. Strong analytical thinking, komunikasi baik untuk presentasi hasil analisis.', 'Jakarta Pusat', 'DKI Jakarta', 'Jakarta Pusat', NULL, '6-10 juta', 6, 10, 'full_time', 's1', 0, NULL, NULL, '["Excel","SQL","Python","Tableau"]', '["BPJS","THR","Gaji 13"]', @hr_id),
('Product Manager', 'Memimpin pengembangan produk dari riset hingga launch. Product strategy, Agile, user research.', 'Product Manager akan memimpin seluruh siklus hidup produk dari discovery, design, development, hingga launch dan iterasi. Anda menjadi suara customer di dalam tim dan memastikan produk yang dibangun memberikan value yang tepat.\n\nTanggung jawab: Melakukan user research dan competitive analysis, mendefinisikan roadmap dan prioritas, menulis PRD dan user stories, bekerja erat dengan engineering dan design, menganalisis metrik produk dan melakukan A/B testing. Familiar dengan metodologi Agile, tools seperti Jira, serta frameworks product management.\n\nProfil ideal: 3+ tahun experience, komunikasi excellent, analytical thinking, stakeholder management, dan passion untuk membangun produk yang impactful.', 'Jakarta Barat', 'DKI Jakarta', 'Jakarta Barat', NULL, '15-25 juta', 15, 25, 'full_time', 's1', 0, NULL, NULL, '["Product Strategy","Agile","Jira","User Research"]', '["BPJS","THR","Bonus"]', @hr_id),
('UI/UX Designer', 'Mendesain interface yang user-friendly dengan Figma. Prototyping dan user research. Portofolio wajib.', 'UI/UX Designer bertugas menciptakan pengalaman pengguna yang intuitif dan menyenangkan. Anda akan mendesain interface untuk web dan mobile, mulai dari wireframe hingga high-fidelity prototype.\n\nRequirements: Mahir Figma (atau Sketch/Adobe XD), mampu membuat prototype interaktif, memahami prinsip UX (user flows, information architecture, usability). Pengalaman melakukan user research dan usability testing. Sense of visual design yang baik, typography, color theory, dan design system.\n\nPortofolio wajib dilampirkan. Pengalaman dengan design system dan collaboration dengan developer adalah nilai plus. Kami menyediakan remote working dan asuransi kesehatan.', 'Bandung', 'Jawa Barat', 'Bandung', NULL, '7-12 juta', 7, 12, 'full_time', 's1', 0, NULL, NULL, '["Figma","Prototyping","User Research"]', '["BPJS","Remote","Asuransi"]', @hr_id),
('Backend Developer', 'Membangun API dan sistem backend. Node.js, Python, Go. PostgreSQL, cloud AWS/GCP.', 'Backend Developer bertanggung jawab membangun dan memelihara sistem server, API, dan integrasi database. Anda akan bekerja dengan arsitektur yang scalable dan maintainable.\n\nTech stack: Node.js, Python, atau Go. Database PostgreSQL/MySQL. Experience dengan cloud (AWS, GCP) - EC2, Lambda, RDS, S3. Memahami RESTful API design, authentication (JWT, OAuth), caching (Redis), message queue. Familiar dengan Docker dan CI/CD.\n\nAnda akan berkolaborasi dengan frontend dan DevOps untuk deliver fitur end-to-end. Kami mencari problem-solver yang senang belajar teknologi baru. Benefit: Laptop provided, BPJS, THR.', 'Surabaya', 'Jawa Timur', 'Surabaya', NULL, '10-18 juta', 10, 18, 'full_time', 's1', 0, NULL, NULL, '["Node.js","Python","PostgreSQL","AWS"]', '["BPJS","THR","Laptop"]', @hr_id),
('Content Writer', 'Menulis konten blog, sosial media, marketing. Bahasa Indonesia & Inggris. Basic SEO.', 'Content Writer menciptakan konten yang menarik dan informatif untuk berbagai channel: blog, social media, email marketing, dan website. Konten yang Anda tulis akan mendukung brand awareness dan engagement.\n\nRequirements: Mahir menulis dalam Bahasa Indonesia dan Inggris. Memahami dasar-dasar SEO (keyword research, on-page SEO). Pengalaman menulis untuk blog, social media copy, atau marketing materials. Creative, mampu menyesuaikan tone of voice brand, dan meet deadline.\n\nPosisi freelance dengan jam kerja fleksibel. Remote work sepenuhnya. Ideal untuk yang senang menulis dan ingin berkontribusi pada growth perusahaan melalui konten.', 'Remote', NULL, NULL, NULL, '5-8 juta', 5, 8, 'freelance', 's1', 0, NULL, NULL, '["Content Writing","SEO","Bahasa Inggris"]', '["WFH","Flexible Hours"]', @hr_id),
('HR Specialist', 'Rekrutmen, onboarding, administrasi HR. HRIS, payroll. Pengalaman minimal 2 tahun.', 'HR Specialist mendukung seluruh siklus HR: recruitment, onboarding, administrasi karyawan, hingga payroll. Anda menjadi contact person untuk kebutuhan SDM di perusahaan.\n\nTanggung jawab: End-to-end recruitment (sourcing, screening, interview, offer). Onboarding karyawan baru. Handle administrasi (cuti, absensi, kontrak). Bantuan payroll dan benefit. Familiar dengan HRIS dan pengelolaan dokumen HR.\n\nKualifikasi: S1 Psikologi, Manajemen, atau bidang terkait. Minimal 2 tahun pengalaman di HR. Detail-oriented, komunikasi baik, discrete dengan data sensitif. Training dan development opportunity disediakan.', 'Tangerang', 'Banten', 'Tangerang', NULL, '7-11 juta', 7, 11, 'full_time', 's1', 0, NULL, NULL, '["Rekrutmen","HRIS","Payroll"]', '["BPJS","THR","Training"]', @hr_id),
('DevOps Engineer', 'CI/CD, Docker, Kubernetes, cloud infrastructure. Linux dan scripting wajib. Urgent.', 'DevOps Engineer membangun dan memelihara infrastruktur cloud, pipeline CI/CD, serta sistem monitoring. Anda memastikan aplikasi berjalan stabil, scalable, dan aman.\n\nTech stack: Docker, Kubernetes, AWS/GCP. CI/CD dengan Jenkins, GitHub Actions, atau GitLab CI. Infrastructure as Code (Terraform, Ansible). Monitoring (Prometheus, Grafana, ELK). Linux administration, scripting (Bash, Python). Network dan security basics.\n\nAnda akan berkolaborasi dengan development team untuk automate deployment dan improve reliability. Posisi urgent. Benefit: Laptop, WFH hybrid, BPJS, THR. Max 30 applicants.', 'Jakarta', 'DKI Jakarta', 'Jakarta Selatan', NULL, '12-20 juta', 12, 20, 'full_time', 's1', 1, NULL, 30, '["Docker","Kubernetes","AWS","Terraform"]', '["BPJS","THR","Laptop","WFH"]', @hr_id),
('Marketing Specialist', 'Campaign digital, social media, branding. Google Ads, Meta Ads. Target-driven.', 'Marketing Specialist menjalankan campaign digital untuk akuisisi customer dan brand awareness. Anda bertanggung jawab atas performance marketing channels dan mencapai target yang ditetapkan.\n\nTanggung jawab: Plan dan execute campaign (Google Ads, Meta Ads, TikTok Ads). Social media management dan content planning. Analytics dan reporting (GA4, Ads dashboard). A/B testing dan optimasi. Koordinasi dengan creative team untuk assets.\n\nProfil: Pengalaman 1+ tahun di digital marketing. Familiar dengan Google Ads, Meta Business Suite, analytics tools. Data-driven, creative, mampu bekerja dengan target. Commission berdasarkan performance.', 'Jakarta Timur', 'DKI Jakarta', 'Jakarta Timur', NULL, '6-10 juta', 6, 10, 'full_time', 's1', 0, NULL, NULL, '["Digital Marketing","Google Ads","Meta Ads"]', '["BPJS","THR","Comission"]', @hr_id),
('Quality Assurance Engineer', 'Testing manual dan otomasi. Selenium, Cypress. Attention to detail penting.', 'QA Engineer memastikan kualitas produk software melalui testing manual dan otomasi. Anda adalah garda terakhir sebelum release ke production.\n\nTanggung jawab: Merancang dan menjalankan test cases. Manual testing untuk fitur baru dan regression. Otomasi testing dengan Selenium, Cypress, atau sejenisnya. Bug reporting dan tracking. Kolaborasi dengan developer untuk reproduce dan verify fix.\n\nKualifikasi: D3/S1. Pengalaman QA atau software testing. Familiar dengan testing methodology, bug tracking tools (Jira, etc). Logical thinking, attention to detail, komunikasi jelas. Passion untuk quality.', 'Jakarta Selatan', 'DKI Jakarta', 'Jakarta Selatan', NULL, '6-11 juta', 6, 11, 'full_time', 'd3', 0, NULL, NULL, '["QA","Selenium","Manual Testing"]', '["BPJS","THR"]', @hr_id),
('Mobile Developer', 'Pengembangan app Android/iOS. Kotlin, Swift, atau React Native/Flutter.', 'Mobile Developer membangun aplikasi mobile native (Android/iOS) atau cross-platform. Anda akan mengembangkan produk yang digunakan oleh jutaan user.\n\nTech stack: Native - Kotlin (Android), Swift (iOS). Cross-platform - React Native atau Flutter. Memahami mobile UI/UX best practices, API integration, offline storage, push notifications. Familiar dengan app store deployment process.\n\nAnda akan bekerja dalam agile team, berkolaborasi dengan backend dan design. Kami mencari developer yang passionate tentang mobile dan user experience. Benefit: Laptop, BPJS, THR.', 'Bandung', 'Jawa Barat', 'Bandung', NULL, '9-15 juta', 9, 15, 'full_time', 's1', 0, NULL, NULL, '["Kotlin","Swift","Flutter","React Native"]', '["BPJS","THR","Laptop"]', @hr_id),
('Business Development', 'Mencari partner bisnis, negosiasi, proposal. B2B sales preferred.', 'Business Development mengidentifikasi dan menjalin kerjasama dengan partner bisnis, enterprise clients, dan channel. Anda bertanggung jawab untuk generate revenue melalui partnership dan deal closure.\n\nTanggung jawab: Prospect dan outreach ke potential partners. Pitch presentasi, negosiasi, dan proposal. Build relationship jangka panjang. Coordinate dengan product dan legal untuk deal structure. Achieve target revenue/partnership.\n\nProfil: Pengalaman sales atau business development, B2B preferred. Strong communication, negotiation, dan networking. Self-driven, target-oriented. Commission based on closed deals.', 'Jakarta Pusat', 'DKI Jakarta', 'Jakarta Pusat', NULL, '8-14 juta', 8, 14, 'full_time', 's1', 0, NULL, NULL, '["Sales","Negosiasi","B2B"]', '["BPJS","THR","Comission"]', @hr_id),
('Graphic Designer', 'Mendesain visual untuk branding, social media, marketing. Adobe Creative Suite.', 'Graphic Designer menciptakan visual yang menarik untuk berbagai kebutuhan: branding, social media content, marketing materials, dan internal communication. Anda memastikan konsistensi visual brand di semua touchpoint.\n\nRequirements: Mahir Adobe Creative Suite (Photoshop, Illustrator, InDesign). Familiar dengan Canva untuk quick assets. memahami typography, color theory, composition. Kreatif, mampu interpret brief menjadi visual yang impactful. Pengalaman desain untuk digital dan print.\n\nAnda akan bekerja dengan marketing dan content team. WFH hybrid tersedia. Portofolio wajib dilampirkan.', 'Tangerang Selatan', 'Banten', 'Tangerang Selatan', NULL, '5-9 juta', 5, 9, 'full_time', 'sma', 0, NULL, NULL, '["Photoshop","Illustrator","Canva"]', '["BPJS","WFH"]', @hr_id),
('Accountant', 'Laporan keuangan, pajak, pembukuan. Software akuntansi. Pengalaman minimal 2 tahun.', 'Accountant bertanggung jawab atas accurate financial recording, reporting, dan compliance. Anda memastikan laporan keuangan tepat waktu dan sesuai standar akuntansi.\n\nTanggung jawab: Pembukuan harian (AP, AR, journal entries). Penyusunan laporan keuangan bulanan dan tahunan. Handle perpajakan (PPh, PPN, SPT). Rekonsiliasi bank dan general ledger. Coordinate dengan auditor saat audit.\n\nKualifikasi: S1 Akuntansi. Minimal 2 tahun pengalaman. Familiar dengan software akuntansi (SAP, Jurnal, Accurate, atau sejenis). Detail-oriented, integritas tinggi. Brevet A/B nilai plus. Benefit: BPJS, THR, asuransi.', 'Jakarta Barat', 'DKI Jakarta', 'Jakarta Barat', NULL, '7-12 juta', 7, 12, 'full_time', 's1', 0, NULL, NULL, '["Akuntansi","Pajak","SAP"]', '["BPJS","THR","Asuransi"]', @hr_id),
('Social Media Specialist', 'Manage akun social media, content planning, engagement. Kreatif, update dengan tren.', 'Social Media Specialist mengelola presence brand di berbagai platform (Instagram, TikTok, LinkedIn, dll). Anda bertanggung jawab untuk content calendar, posting, dan engagement dengan audience.\n\nTanggung jawab: Content planning dan scheduling. Create dan curate content (copy, basic design dengan Canva). Community management dan respond comments/DM. Analytics dan reporting engagement. Kolaborasi dengan content creator bila perlu.\n\nProfil: Kreatif, up-to-date dengan tren social media. Familiar dengan fitur dan algorithm setiap platform. Copywriting basic. Posisi part-time, remote, jam fleksibel. Ideal untuk yang passionate di social media.', 'Remote', NULL, NULL, NULL, '4-7 juta', 4, 7, 'part_time', 'sma', 0, NULL, NULL, '["Social Media","Content Planning","Canva"]', '["WFH","Flexible"]', @hr_id),
('Customer Success', 'Onboarding, support, retention pelanggan. Komunikasi dan empati penting.', 'Customer Success memastikan pelanggan mendapatkan value maksimal dari produk dan tetap puas. Anda adalah bridge antara customer dan internal team.\n\nTanggung jawab: Onboarding customer baru dan training. Proactive check-in untuk usage dan satisfaction. Handle escalation dan complaint. Identify upsell/expansion opportunity. Work dengan sales dan product untuk improve experience.\n\nKualifikasi: Excellent communication dan empathy. Experience dengan CRM (HubSpot, Salesforce, dll). Problem-solving, customer-oriented. S1. Pengalaman di customer success, account management, atau support premium adalah nilai plus.', 'Jakarta Selatan', 'DKI Jakarta', 'Jakarta Selatan', NULL, '6-10 juta', 6, 10, 'full_time', 's1', 0, NULL, NULL, '["Customer Service","CRM","Komunikasi"]', '["BPJS","THR"]', @hr_id),
('Data Scientist', 'ML, statistik, modeling. Python, SQL, TensorFlow/PyTorch. Research atau industry exp.', 'Data Scientist membangun model machine learning dan analisis statistik untuk solve business problems. Anda mengubah data menjadi predictive dan prescriptive insights.\n\nTanggung jawab: Eksplorasi data, feature engineering. Develop dan deploy ML models (classification, regression, NLP, recommendation). A/B test design dan analysis. Kolaborasi dengan engineering untuk productionize model. Research dan implement state-of-the-art approaches.\n\nTech: Python, SQL, TensorFlow/PyTorch, scikit-learn. Pengalaman dengan big data tools (Spark) nilai plus. S2 preferred, atau S1 + strong ML experience. Benefit: Laptop, conference budget, BPJS, THR.', 'Jakarta', 'DKI Jakarta', 'Jakarta Selatan', 'Kebayoran Baru', '15-25 juta', 15, 25, 'full_time', 's2', 0, NULL, NULL, '["Python","Machine Learning","SQL","TensorFlow"]', '["BPJS","THR","Laptop","Conference"]', @hr_id),
('Legal Officer', 'Drafting kontrak, compliance, legal opinion. Exp di perusahaan/startup tech.', 'Legal Officer menyediakan dukungan hukum untuk operasional perusahaan: kontrak, compliance, corporate governance, dan legal risk management. Anda memastikan bisnis berjalan dalam koridor regulasi.\n\nTanggung jawab: Draft dan review berbagai jenis kontrak (kerjasama, NDA, employment, vendor). Legal research dan opini hukum. Memantau compliance dengan regulasi (UU PDP, OJK bila applicable, dll). Coordinate dengan external counsel bila perlu. Advise management untuk keputusan dengan implikasi legal.\n\nKualifikasi: S1 Hukum. Pengalaman 2+ tahun, preferably di perusahaan atau startup tech. Strong drafting skill, analytical. Lisensi PERADI nilai plus. Benefit: BPJS, THR, asuransi.', 'Jakarta Pusat', 'DKI Jakarta', 'Jakarta Pusat', NULL, '10-18 juta', 10, 18, 'full_time', 's1', 0, NULL, NULL, '["Legal","Kontrak","Compliance"]', '["BPJS","THR","Asuransi"]', @hr_id),
('Office Admin', 'Administrasi kantor, surat-menyurat, meeting, inventory. Teliti dan terorganisir.', 'Office Admin menjaga kelancaran operasional kantor sehari-hari. Anda menjadi titik koordinasi untuk kebutuhan administratif dan logistic kantor.\n\nTanggung jawab: Surat-menyurat dan filing. Koordinasi meeting (scheduling, room booking, notulen). Pengelolaan inventory kantor dan supply. Receive tamu dan telepon. Dukungan administrasi untuk tim (travel, perjalanan dinas). Berkoordinasi dengan building management.\n\nKualifikasi: D3. Familiar Microsoft Office. Teliti, terorganisir, komunikasi baik. Dapat multitasking. Pengalaman sebagai admin kantor atau secretary adalah nilai plus.', 'Tangerang', 'Banten', 'Tangerang', NULL, '4-6 juta', 4, 6, 'full_time', 'd3', 0, NULL, NULL, '["Administrasi","Microsoft Office","Koordinasi"]', '["BPJS","THR"]', @hr_id),
('IT Support', 'Support teknis internal, troubleshooting, maintenance. Windows/Linux, jaringan.', 'IT Support menyediakan technical support untuk karyawan internal. Anda memastikan hardware, software, dan jaringan berjalan lancar sehingga tim dapat fokus bekerja.\n\nTanggung jawab: Troubleshooting hardware (PC, laptop, printer) dan software. Setup dan maintain user account, email, access. Basic network troubleshooting (connectivity, VPN). Asset management IT. Escalation ke vendor bila perlu. Dokumentasi dan knowledge base untuk common issues.\n\nKualifikasi: D3 IT/Computer. Familiar Windows dan Linux. Basic networking. Customer service oriented, sabar, problem-solving. Pengalaman IT support atau helpdesk nilai plus.', 'Bandung', 'Jawa Barat', 'Bandung', NULL, '5-8 juta', 5, 8, 'full_time', 'd3', 0, NULL, NULL, '["IT Support","Networking","Troubleshooting"]', '["BPJS","THR"]', @hr_id),
('Sales Executive', 'Capai target penjualan, build pipeline, presentasi. Strong communication skills.', 'Sales Executive mengembangkan pipeline penjualan dan menutup deal dengan customer. Anda bertanggung jawab untuk mencapai target revenue melalui direct selling atau channel.\n\nTanggung jawab: Prospect dan qualify leads. Presentasi produk ke prospect. Negosiasi dan closing. Maintain relationship dengan existing customer. Update CRM dan sales report. Coordinate dengan marketing untuk lead generation.\n\nProfil: Strong communication dan persuasion. Target-driven, resilient. Pengalaman sales B2B atau B2C. mampu presentasi dengan confidence. Commission based on achievement. BPJS, THR.', 'Surabaya', 'Jawa Timur', 'Surabaya', NULL, '6-10 juta', 6, 10, 'full_time', 'sma', 0, NULL, NULL, '["Sales","Komunikasi","Negosiasi"]', '["BPJS","THR","Comission"]', @hr_id),
('Full Stack Developer', 'End-to-end dev. React/Vue + Node/PHP, database. Fast learner, team player.', 'Full Stack Developer membangun aplikasi web dari frontend hingga backend. Anda memiliki visi lengkap dari UI sampai database dan deployment.\n\nTech stack: Frontend - React atau Vue, HTML/CSS, TypeScript. Backend - Node.js atau PHP (Laravel). Database PostgreSQL/MySQL. RESTful API, authentication. Basic DevOps (Docker, deploy). Git, testing.\n\nAnda akan own fitur end-to-end, berkolaborasi dengan designer dan PM. Kami mencari fast learner yang senang explore teknologi baru. Laptop provided, WFH hybrid, BPJS, THR.', 'Jakarta', 'DKI Jakarta', 'Jakarta Timur', 'Jatinegara', '10-16 juta', 10, 16, 'full_time', 's1', 0, NULL, NULL, '["React","Node.js","PHP","PostgreSQL"]', '["BPJS","THR","WFH","Laptop"]', @hr_id),
('SEO Specialist', 'Optimasi SEO on-page dan off-page. Keyword research, link building, analytics.', 'SEO Specialist meningkatkan organic traffic website melalui optimasi search engine. Anda mengimplementasikan strategi SEO yang sustainable dan measurable.\n\nTanggung jawab: Keyword research dan content gap analysis. On-page SEO (meta, structure, content optimization). Technical SEO (site speed, crawlability, schema). Off-page SEO dan link building. Monitoring ranking, traffic, dengan Google Analytics/Search Console. Report dan rekomendasi.\n\nProfil: Pengalaman SEO 1+ tahun. Familiar dengan tools (Ahrefs, SEMrush, GA4, GSC). Understanding algoritma search. Data-driven. Posisi freelance, WFH, flexible. Portfolio/case study wajib.', 'Remote', NULL, NULL, NULL, '5-9 juta', 5, 9, 'freelance', 's1', 0, NULL, NULL, '["SEO","Keyword Research","Google Analytics"]', '["WFH","Flexible"]', @hr_id),
('Copywriter', 'Menulis copy untuk iklan, landing page, email. Creative dan persuasive.', 'Copywriter menciptakan copy yang menjual - dari headline iklan, landing page, sampai email marketing. Setiap kata dirancang untuk convert dan build brand voice.\n\nTanggung jawab: Write copy untuk ads (Google, Meta, dll), landing pages, sales pages. Email marketing copy (newsletter, nurture, campaign). Social media copy. Collaborate dengan designer untuk kampanye. A/B test copy untuk optimasi.\n\nProfil: Creative, persuasive writing. Memahami copywriting framework (AIDA, PAS, dll). Basic marketing funnel knowledge. Portfolio dengan hasil campaign. WFH hybrid. S1 preferred.', 'Jakarta Selatan', 'DKI Jakarta', 'Jakarta Selatan', NULL, '5-8 juta', 5, 8, 'full_time', 's1', 0, NULL, NULL, '["Copywriting","Creative Writing","Email Marketing"]', '["BPJS","WFH"]', @hr_id),
('Project Coordinator', 'Koordinasi tim dan stakeholder, tracking progress, reporting. Agile, Jira.', 'Project Coordinator memastikan project berjalan on track - schedule, scope, dan koordinasi antar tim. Anda adalah central point untuk update dan communication.\n\nTanggung jawab: Schedule dan milestone tracking. Coordinate meeting dan follow-up action items. Update stakeholder tentang progress. Manage risiko dan blocker. Dokumentasi project. Familiar dengan Agile/Scrum ceremonies dan tools (Jira, Trello, dll).\n\nProfil: Organised, detail-oriented, komunikasi excellent. Dapat manage multiple stakeholders. S1. Pengalaman project coordination atau PM support. Understanding basic project management methodology.', 'Jakarta Barat', 'DKI Jakarta', 'Jakarta Barat', NULL, '7-11 juta', 7, 11, 'full_time', 's1', 0, NULL, NULL, '["Project Management","Agile","Jira"]', '["BPJS","THR"]', @hr_id),
('Intern - Software Development', 'Magang untuk mahasiswa. Belajar development, code review, deployment. Stipend tersedia.', 'Program magang untuk mahasiswa semester akhir yang ingin belajar software development di environment production. Anda akan dibimbing mentor dan berkontribusi pada project nyata.\n\nApa yang akan Anda pelajari: Development workflow (Git, branching, PR). Code review process. Basic deployment. Best practices (testing, documentation). Collaboration dengan tim engineering.\n\nRequirements: Mahasiswa S1 Teknik/CS semester 6+. Basic JavaScript, HTML/CSS. Eager to learn, responsible. Duration 3-6 bulan. Stipend. Certificate dan potential conversion ke full-time. Max 5 slots.', 'Jakarta Pusat', 'DKI Jakarta', 'Jakarta Pusat', NULL, 'Stipend', 2, 4, 'internship', 's1', 0, NULL, 5, '["JavaScript","Git"]', '["Mentoring","Certificate"]', @hr_id),
('Video Editor', 'Editing video untuk konten digital, iklan, social media. Premiere, Final Cut, DaVinci.', 'Video Editor mengedit konten video untuk berbagai keperluan: sosial media, iklan, internal, dan campaign. Anda mengubah raw footage menjadi konten yang engaging.\n\nTanggung jawab: Edit video sesuai brief dan timeline. Color grading, sound design basic. Motion graphics bila diperlukan. Format untuk berbagai platform (16:9, 1:1, 9:16). Coordination dengan creative team.\n\nRequirements: Mahir Premiere Pro, Final Cut, atau DaVinci Resolve. Basic motion graphics (After Effects) nilai plus. Sense of pacing dan storytelling. Portofolio wajib. Posisi part-time, project-based. WFH possible.', 'Jakarta Timur', 'DKI Jakarta', 'Jakarta Timur', NULL, '5-9 juta', 5, 9, 'part_time', 'sma', 0, NULL, NULL, '["Video Editing","Premiere Pro","Motion Graphics"]', '["WFH","Project Based"]', @hr_id),
('Database Administrator', 'Maintenance DB, tuning, backup, security. MySQL/PostgreSQL/Oracle.', 'Database Administrator memastikan database berjalan optimal, aman, dan tersedia. Anda menjaga health dan performance dari data infrastructure.\n\nTanggung jawab: Install, configure, maintain database (MySQL, PostgreSQL, atau Oracle). Performance tuning dan query optimization. Backup dan recovery procedures. Security (access control, encryption). Monitoring dan capacity planning. Collaborate dengan developer untuk schema dan optimization.\n\nKualifikasi: S1. Pengalaman 2+ tahun sebagai DBA. Deep knowledge SQL, indexing, replication. Experience dengan cloud DB (RDS, Cloud SQL) nilai plus. Benefit: Laptop, BPJS, THR.', 'Surabaya', 'Jawa Timur', 'Surabaya', NULL, '11-18 juta', 11, 18, 'full_time', 's1', 0, NULL, NULL, '["MySQL","PostgreSQL","Backup","Security"]', '["BPJS","THR","Laptop"]', @hr_id),
('Research Analyst', 'Riset pasar, kompetitor, tren industri. Report dan rekomendasi untuk product.', 'Research Analyst melakukan riset mendalam untuk mendukung keputusan bisnis dan product. Anda menghasilkan insight yang actionable dari data pasar dan kompetitor.\n\nTanggung jawab: Market research (size, trend, opportunity). Competitor analysis. User/customer research. Secondary research dan synthesis. Report writing dan presentasi. Collaborate dengan product, strategy, dan leadership.\n\nProfil: S1. Strong analytical dan research skills. Excellent writing dan presentation. Sumber data yang kredibel. Curious, detail-oriented. Pengalaman di research, consulting, atau strategy adalah nilai plus. BPJS, THR.', 'Bandung', 'Jawa Barat', 'Bandung', NULL, '6-10 juta', 6, 10, 'full_time', 's1', 0, NULL, NULL, '["Research","Analytics","Report Writing"]', '["BPJS","THR"]', @hr_id),
('Community Manager', 'Membangun komunitas, engagement, event, moderasi. Passion di tech/startup community.', 'Community Manager mengembangkan dan memelihara komunitas user dan enthusiast. Anda menciptakan engagement, sense of belonging, dan mendorong advocacy.\n\nTanggung jawab: Strategi community growth. Daily engagement di channel (Discord, Telegram, forum, social). Moderation dan community guideline. Event planning (online/offline). Gather feedback dan voice of community ke internal. Ambassador program dan user-generated content.\n\nProfil: Outgoing, excellent communication. Pengalaman manage community atau event. Passion untuk tech/startup ecosystem. WFH hybrid. S1 preferred.', 'Jakarta Selatan', 'DKI Jakarta', 'Jakarta Selatan', NULL, '5-8 juta', 5, 8, 'full_time', 's1', 0, NULL, NULL, '["Community","Event","Social Media"]', '["BPJS","WFH"]', @hr_id),
('Scrum Master', 'Fasilitasi agile ceremonies, remove blockers, coaching tim. CSM preferred.', 'Scrum Master memfasilitasi tim agile untuk deliver value secara efektif. Anda memastikan proses berjalan smooth dan tim fokus pada outcome.\n\nTanggung jawab: Facilitate sprint planning, daily standup, retrospective, demo. Remove blockers dan impediments. Shield tim dari gangguan eksternal. Coaching tim pada Agile/Scrum practices. Metrics dan reporting (velocity, burndown). Collaborate dengan PO untuk backlog health.\n\nProfil: Certified Scrum Master (CSM/PSM) preferred. Pengalaman 2+ tahun sebagai SM atau dalam agile team. Excellent facilitation dan conflict resolution. Understanding technical environment. Benefit: BPJS, THR, certification support.', 'Jakarta', 'DKI Jakarta', 'Jakarta Selatan', NULL, '12-18 juta', 12, 18, 'full_time', 's1', 0, NULL, NULL, '["Scrum","Agile","Jira","Coaching"]', '["BPJS","THR","Certification"]', @hr_id),
('Operations Manager', 'Awasi operasional harian, SOP, efficiency. Pengalaman 3+ tahun operations.', 'Operations Manager mengawasi operasional harian untuk memastikan efisiensi, quality, dan compliance. Anda memastikan proses berjalan sesuai SOP dan continuously improve.\n\nTanggung jawab: Oversee daily operations. Develop dan update SOP. Monitor KPIs dan implement corrective action. Resource planning dan scheduling. Coordinate antar departemen. Leadership untuk ops team. Vendor management bila applicable.\n\nKualifikasi: S1. Minimal 3 tahun di operations atau similar. Strong leadership, problem-solving. Process-oriented, data-driven. Experience dengan operations di tech/e-commerce/startup nilai plus. BPJS, THR, performance bonus.', 'Tangerang', 'Banten', 'Tangerang', NULL, '12-20 juta', 12, 20, 'full_time', 's1', 0, NULL, NULL, '["Operations","SOP","Leadership"]', '["BPJS","THR","Bonus"]', @hr_id),
('Technical Writer', 'Dokumentasi teknis, user guide, API docs. Confluence, Markdown. WFH.', 'Technical Writer membuat dokumentasi yang jelas dan mudah diikuti - untuk developer (API docs, SDK), internal (runbooks), dan end user (help, guides).\n\nTanggung jawab: Write dan maintain technical documentation. API documentation (OpenAPI/Swagger). User guides dan tutorials. Internal wiki (Confluence, Notion). Work dengan engineering untuk accuracy. Simplify complex technical concepts.\n\nProfil: Strong technical writing. Dapat memahami technical concepts. Familiar Markdown, Confluence, docs-as-code. Experience dengan API documentation. S1. Remote freelance. WFH, flexible schedule.', 'Remote', NULL, NULL, NULL, '6-10 juta', 6, 10, 'freelance', 's1', 0, NULL, NULL, '["Technical Writing","Confluence","API Docs"]', '["WFH","Flexible"]', @hr_id),
('Brand Manager', 'Strategi branding, positioning, campaign. Pengalaman 4+ tahun brand/marketing.', 'Brand Manager memimpin strategi brand - positioning, identity, dan campaign yang membangun awareness dan equity. Anda memastikan brand konsisten dan impactful di semua touchpoint.\n\nTanggung jawab: Brand strategy dan positioning. Develop brand guidelines. Lead brand campaign end-to-end. Market research untuk brand health. Collaborate dengan marketing, product, creative. Budget management untuk brand initiatives.\n\nKualifikasi: S1. Minimal 4 tahun di brand atau marketing management. Strategic thinking, creative. Strong stakeholder management. Portfolio dengan brand/campaign success. BPJS, THR, performance bonus.', 'Jakarta Pusat', 'DKI Jakarta', 'Jakarta Pusat', NULL, '15-25 juta', 15, 25, 'full_time', 's1', 0, NULL, NULL, '["Brand Strategy","Marketing","Campaign"]', '["BPJS","THR","Bonus"]', @hr_id),
('Finance Analyst', 'Analisis keuangan, budgeting, forecasting. Excel advanced, BI. Exp 2+ tahun.', 'Finance Analyst menyediakan analisis keuangan untuk support strategic decision. Anda membangun model, forecast, dan report yang mendukung planning dan performance management.\n\nTanggung jawab: Financial modeling dan analysis. Budgeting dan forecasting. Variance analysis dan commentary. Management reporting. Support business case dan investment analysis. Ad-hoc analysis untuk leadership.\n\nKualifikasi: S1 Finance/Accounting. Minimal 2 tahun sebagai finance analyst. Advanced Excel, BI tools (Tableau, Power BI). Strong analytical, attention to detail. BPJS, THR, asuransi kesehatan.', 'Jakarta Barat', 'DKI Jakarta', 'Jakarta Barat', NULL, '8-14 juta', 8, 14, 'full_time', 's1', 0, NULL, NULL, '["Finance","Excel","Budgeting"]', '["BPJS","THR","Asuransi"]', @hr_id),
('Security Engineer', 'Security infra, penetration testing, audit. CEH/OSCP preferred. Urgent, max 20 applicants.', 'Security Engineer melindungi infrastruktur dan aplikasi dari ancaman. Anda melakukan assessment, implementasi kontrol, dan response terhadap security incidents.\n\nTanggung jawab: Security assessment dan penetration testing. Implement dan maintain security tools (SIEM, WAF, EDR). Vulnerability management. Security awareness dan policy. Incident response. Collaborate dengan DevOps dan development.\n\nKualifikasi: S1. Pengalaman di cybersecurity. Familiar penetration testing, security frameworks. Certified (CEH, OSCP, dll) strongly preferred. Urgent hiring. Max 20 applicants. Laptop, certification support, BPJS, THR.', 'Jakarta', 'DKI Jakarta', 'Jakarta Selatan', NULL, '15-25 juta', 15, 25, 'full_time', 's1', 1, NULL, 20, '["Security","Penetration Testing","SIEM"]', '["BPJS","THR","Laptop","Certification"]', @hr_id),
('HR Recruiter', 'End-to-end recruitment: sourcing, screening, interview, offer. ATS familiar.', 'HR Recruiter menangani full cycle recruitment untuk berbagai posisi. Anda menemukan dan merekrut talent terbaik yang match dengan kebutuhan perusahaan.\n\nTanggung jawab: Sourcing (job portal, LinkedIn, referral, headhunt). Screening CV dan phone screen. Coordinate interview dengan hiring manager. Assessment dan offer process. Candidate experience. Maintain pipeline dan report. Familiar dengan ATS.\n\nProfil: S1. Pengalaman recruitment 1+ tahun. Strong sourcing dan interviewing skill. Communication excellent. Target-oriented (time-to-hire, quality-of-hire). BPJS, THR.', 'Surabaya', 'Jawa Timur', 'Surabaya', NULL, '6-10 juta', 6, 10, 'full_time', 's1', 0, NULL, NULL, '["Recruitment","Sourcing","Interviewing"]', '["BPJS","THR"]', @hr_id),
('Growth Hacker', 'User acquisition, retention, experimentation. Data-driven, analytics tools.', 'Growth Hacker memacu pertumbuhan user dan revenue melalui eksperimen yang data-driven. Anda mengidentifikasi leverage points dan menjalankan initiative untuk scale.\n\nTanggung jawab: Growth strategy dan experimentation roadmap. A/B testing dan optimization. Funnel analysis dan improvement. Acquisition channels (organic, paid, referral). Retention dan engagement initiatives. Analytics dan reporting. Work dengan product, marketing, engineering.\n\nProfil: Data-driven, creative problem solver. Familiar analytics (GA, Mixpanel, Amplitude), A/B testing. Experience growth atau growth marketing. S1. WFH hybrid. BPJS, THR.', 'Jakarta Timur', 'DKI Jakarta', 'Jakarta Timur', NULL, '10-18 juta', 10, 18, 'full_time', 's1', 0, NULL, NULL, '["Growth","Analytics","A/B Testing"]', '["BPJS","THR","WFH"]', @hr_id),
('Support Engineer', 'Technical support produk SaaS. Troubleshooting, dokumentasi, escalation.', 'Support Engineer memberikan technical support untuk customer yang menggunakan produk SaaS kami. Anda memecahkan masalah teknis dan memastikan customer sukses.\n\nTanggung jawab: Handle technical inquiries dan troubleshooting. Reproduce dan diagnose issues. Create bug reports dan escalate ke development. Dokumentasi FAQ dan knowledge base. Work dengan product untuk feedback dan improvement. Meet SLA response dan resolution.\n\nKualifikasi: D3/S1. Technical background - memahami web, API, database basic. Customer-oriented, problem-solving. Pengalaman support SaaS atau software preferred. WFH hybrid. BPJS, THR.', 'Bandung', 'Jawa Barat', 'Bandung', NULL, '6-9 juta', 6, 9, 'full_time', 'd3', 0, NULL, NULL, '["Technical Support","SaaS","Troubleshooting"]', '["BPJS","THR","WFH"]', @hr_id),
('Event Coordinator', 'Plan dan organize event perusahaan. Vendor, logistic, on-site execution.', 'Event Coordinator merencanakan dan melaksanakan event perusahaan - internal (townhall, team building) maupun eksternal (product launch, conference, partner event).\n\nTanggung jawab: Event planning dan timeline. Vendor sourcing dan negotiation. Budget management. Logistic dan venue. On-site coordination dan execution. Post-event evaluation. Collaborate dengan marketing dan leadership untuk event strategy.\n\nProfil: Organised, detail-oriented. Strong coordination dan vendor management. Pengalaman event planning. Stress-resistant, can work under tight deadline. S1. BPJS, THR.', 'Jakarta Selatan', 'DKI Jakarta', 'Jakarta Selatan', NULL, '5-8 juta', 5, 8, 'full_time', 's1', 0, NULL, NULL, '["Event Planning","Koordinasi","Vendor"]', '["BPJS","THR"]', @hr_id),
('Volunteer - Community Teaching', 'Mengajar programming basic ke komunitas. Sukarela. Certificate dan network.', 'Program volunteer untuk mengajar programming dasar ke komunitas (pelajar, mahasiswa, career switcher). Anda berbagi knowledge dan membantu membuka akses ke tech education.\n\nTanggung jawab: Prepare materi dan kurikulum basic (HTML/CSS, JavaScript intro, dll). Mengajar secara online/offline. Mentor peserta. Evaluate dan feedback.\n\nProfil: Berpengalaman programming. Passion untuk teaching dan community. Part-time, sukarela (tanpa kompensasi finansial). Benefit: Certificate, networking, pengalaman mengajar, kontribusi ke komunitas. S1 atau mahasiswa semester akhir.', 'Jakarta Pusat', 'DKI Jakarta', 'Jakarta Pusat', NULL, 'Volunteer', NULL, NULL, 'volunteer', 's1', 0, NULL, NULL, '["Teaching","Programming"]', '["Certificate","Network"]', @hr_id),
('Machine Learning Engineer', 'Build dan deploy ML models. Python, TensorFlow, MLOps. Research/industry exp.', 'Machine Learning Engineer membangun dan productionize model ML yang mendukung produk. Anda bridge antara research dan engineering - dari experiment sampai deployment.\n\nTanggung jawab: Develop ML models (NLP, recommendation, vision, dll). MLOps - deploy, monitor, retrain. Data pipeline untuk training. Optimize model performance (latency, accuracy). Collaborate dengan data scientists dan backend engineers.\n\nTech: Python, TensorFlow/PyTorch, Docker, Kubernetes. Experience dengan cloud ML (SageMaker, Vertex AI) nilai plus. S2 atau S1 + strong ML engineering experience. Laptop, conference budget, BPJS, THR.', 'Jakarta', 'DKI Jakarta', 'Jakarta Selatan', NULL, '18-30 juta', 18, 30, 'full_time', 's2', 0, NULL, NULL, '["Python","TensorFlow","MLOps","Docker"]', '["BPJS","THR","Laptop","Conference"]', @hr_id),
('Logistics Coordinator', 'Koordinasi pengiriman, inventory, vendor. Exp e-commerce/logistics preferred.', 'Logistics Coordinator mengkoordinasikan operasional logistik - pengiriman, penerimaan, inventory, dan koordinasi dengan vendor/courier. Memastikan barang tepat waktu dan akurat.\n\nTanggung jawab: Schedule dan track pengiriman. Inventory management dan stock check. Coordinate dengan warehouse dan courier. Vendor management. Dokumentasi dan reporting. Resolve issue pengiriman.\n\nKualifikasi: D3. Pengalaman di logistics atau e-commerce operations preferred. Detail-oriented, problem-solving. Familiar dengan WMS atau shipping systems nilai plus. BPJS, THR.', 'Tangerang', 'Banten', 'Tangerang', NULL, '5-8 juta', 5, 8, 'full_time', 'd3', 0, NULL, NULL, '["Logistics","Inventory","Koordinasi"]', '["BPJS","THR"]', @hr_id),
('Public Relations', 'Media relations, press release, event PR. Strong writing dan networking.', 'Public Relations mengelola reputasi dan exposure perusahaan melalui media, event, dan strategic communication. Anda membangun relationship dengan media dan stakeholder eksternal.\n\nTanggung jawab: Media relations dan pitching. Press release dan press kit. Event PR dan media coverage. Crisis communication bila perlu. Monitor media dan sentiment. Klipping dan report. Collaborate dengan marketing untuk integrated campaign.\n\nProfil: S1. Strong writing ( Indonesia & Inggris). Network dengan media/jurnalis. Presentable, networking skill. Pengalaman PR atau corporate communication. BPJS, THR.', 'Jakarta Barat', 'DKI Jakarta', 'Jakarta Barat', NULL, '7-12 juta', 7, 12, 'full_time', 's1', 0, NULL, NULL, '["PR","Media","Writing"]', '["BPJS","THR"]', @hr_id),
('Quality Engineer', 'QA untuk proses manufacturing/operation. ISO, audit, continuous improvement.', 'Quality Engineer memastikan kualitas produk dan proses melalui standard, audit, dan continuous improvement. Anda mengembangkan dan memelihara sistem manajemen mutu.\n\nTanggung jawab: Implement dan maintain QMS (ISO 9001, dll). Conduct internal audit. Root cause analysis untuk quality issues. Develop dan update SOP. Training tim pada quality standards. Coordinate dengan production dan procurement untuk quality control.\n\nKualifikasi: S1 Engineering. Pengalaman di QA/QC atau quality engineering. Familiar ISO standards, audit process. Analytical, detail-oriented. Experience di manufacturing atau operation. BPJS, THR.', 'Bekasi', 'Jawa Barat', 'Bekasi', NULL, '7-11 juta', 7, 11, 'full_time', 's1', 0, NULL, NULL, '["QA","ISO","Audit"]', '["BPJS","THR"]', @hr_id),
('PHP Developer', 'Web development PHP/Laravel. Database, REST API. Min 2 tahun pengalaman.', 'PHP Developer membangun dan maintain aplikasi web dengan PHP dan Laravel. Anda akan develop backend yang robust, secure, dan scalable.\n\nTech stack: PHP 8+, Laravel. MySQL/PostgreSQL. RESTful API design. Git, testing (PHPUnit). Familiar dengan frontend basic (Blade, Vue/React integration). Redis, queue, cache. Deploy (Laravel Forge, Vapor, atau manual).\n\nKualifikasi: S1. Minimal 2 tahun experience PHP/Laravel. Strong OOP, MVC. Understanding security best practices. WFH hybrid. BPJS, THR.', 'Jakarta Selatan', 'DKI Jakarta', 'Jakarta Selatan', 'Kebayoran Baru', '8-14 juta', 8, 14, 'full_time', 's1', 0, NULL, NULL, '["PHP","Laravel","MySQL","REST API"]', '["BPJS","THR","WFH"]', @hr_id),
('Python Developer', 'Backend Python/Django atau Flask. FastAPI, PostgreSQL.', 'Python Developer membangun backend services dengan Python. Anda develop API, microservices, dan integrasi yang mendukung produk.\n\nTech stack: Python 3.x. Django atau Flask. FastAPI untuk high-performance API. PostgreSQL. Redis, Celery untuk async tasks. Testing (pytest). Docker. Experience dengan ML/data pipeline adalah nilai plus.\n\nAnda akan work dengan clean code, documentation, dan best practices. S1. Pengalaman Python backend. Laptop provided. BPJS, THR.', 'Surabaya', 'Jawa Timur', 'Surabaya', NULL, '9-15 juta', 9, 15, 'full_time', 's1', 0, NULL, NULL, '["Python","Django","PostgreSQL"]', '["BPJS","THR","Laptop"]', @hr_id),
('React Developer', 'Frontend React. Redux, TypeScript. Passion untuk clean code dan UX.', 'React Developer membangun single-page applications dengan React. Anda create components yang reusable, performant, dan maintainable.\n\nTech: React (hooks), TypeScript. State management (Redux, Zustand, atau Context). REST/GraphQL integration. Testing (Jest, React Testing Library). Build tools (Vite, Webpack). Styling (CSS Modules, Tailwind, atau styled-components).\n\nProfil: S1. Strong React dan JavaScript/TypeScript. Understanding component design, performance optimization. Clean code, testing. WFH hybrid. BPJS, THR.', 'Bandung', 'Jawa Barat', 'Bandung', NULL, '8-14 juta', 8, 14, 'full_time', 's1', 0, NULL, NULL, '["React","TypeScript","Redux"]', '["BPJS","THR","WFH"]', @hr_id),
('Data Entry', 'Input data ke sistem. Cepat, teliti, Excel. Part-time, jam fleksibel.', 'Data Entry melakukan input dan update data ke sistem dengan akurat dan tepat waktu. Anda memastikan data tersimpan dengan benar untuk keperluan operasional dan reporting.\n\nTanggung jawab: Input data dari berbagai sumber (form, dokumen, Excel) ke sistem. Verifikasi dan validasi data. Update data berkala. Maintain data quality. Koordinasi dengan tim lain untuk kebutuhan data.\n\nProfil: Cepat mengetik, teliti, detail-oriented. Mahir Excel (basic formula, pivot). Dapat bekerja repetitive dengan fokus. Part-time, flexible hours. SMA minimal. Pengalaman data entry nilai plus.', 'Jakarta Timur', 'DKI Jakarta', 'Jakarta Timur', NULL, '3-5 juta', 3, 5, 'part_time', 'sma', 0, NULL, NULL, '["Excel","Data Entry","Teliti"]', '["Flexible Hours"]', @hr_id),
('Warehouse Staff', 'Penerimaan, pengepakan, pengiriman barang. Fisik prima. Forklift license plus.', 'Warehouse Staff menangani operasional gudang - penerimaan barang, pengepakan, pengiriman, dan stock management. Anda memastikan barang keluar-masuk dengan benar dan rapi.\n\nTanggung jawab: Unload dan receive barang. Picking dan packing sesuai order. Loading untuk pengiriman. Stock count dan inventory check. Maintain kebersihan dan kerapian gudang. Update sistem/WMS bila ada.\n\nKualifikasi: SMA. Fisik prima, mampu angkat beban. Teliti, disiplin. Bisa operasikan forklift (license) nilai plus. Experience warehouse atau logistics. BPJS, THR.', 'Bekasi', 'Jawa Barat', 'Bekasi', NULL, '4-6 juta', 4, 6, 'full_time', 'sma', 0, NULL, NULL, '["Warehouse","Logistics","Forklift"]', '["BPJS","THR"]', @hr_id),
('Customer Service Representative', 'Handle inquiry, komplain, order via chat/telepon. Ramah, sabar, problem-solving.', 'Customer Service Representative melayani customer melalui berbagai channel - chat, telepon, email. Anda adalah wajah perusahaan untuk customer, memastikan setiap interaksi positif dan masalah terselesaikan.\n\nTanggung jawab: Response inquiry dan complaint tepat waktu. Proses order dan follow-up. Escalation bila perlu. Update customer tentang status. Maintain quality service (CSAT, response time). Log dan report ke sistem.\n\nProfil: Ramah, sabar, excellent communication. Problem-solving orientation. Dapat handle pressure dan customer yang marah. SMA minimal. Pengalaman CS preferred. BPJS, THR. Shift mungkin diperlukan.', 'Jakarta Pusat', 'DKI Jakarta', 'Jakarta Pusat', NULL, '4-6 juta', 4, 6, 'full_time', 'sma', 0, NULL, NULL, '["Customer Service","Komunikasi","Problem Solving"]', '["BPJS","THR"]', @hr_id);
